
import base64
import sys
import os

# هذا الملف هو محمل تلقائي لسكريبت SELVA_TOOLS
# تم تشفيره لحماية الكود المصدري

encoded_data = ""

def run():
    try:
        # فك التشفير وتنفيذ الكود في الذاكرة دون حفظه كملف
        exec(base64.b64decode(encoded_data).decode(), globals())
    except Exception as e:
        print(f"Error executing script: {e}")

if __name__ == "__main__":
    run()
